@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger d-flex align-items-center" role="alert">
        <span class="me-2">⚠️</span>
        <span>@_error</span>
        <button class="btn btn-sm btn-outline-danger ms-auto" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>@_allTasks.Count</strong><br /><small class="text-muted">Total</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@GetColumnTasks(StatusToDo).Count</strong><br /><small class="text-muted">To Do</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@GetColumnTasks(StatusInProgress).Count</strong><br /><small class="text-muted">In Progress</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@GetColumnTasks(StatusDone).Count</strong><br /><small class="text-muted">Done</small></div></div>
        <div class="col"><div class="card text-center p-2 @(OverdueCount > 0 ? "border-danger" : "")"><strong class="@(OverdueCount > 0 ? "text-danger" : "")">@OverdueCount</strong><br /><small class="text-muted">Overdue</small></div></div>
    </div>

    <!-- Search -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…" @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="row g-3">
        @foreach (var column in Columns)
        {
            var tasks = GetFilteredColumnTasks(column.Status);
            var columnCount = GetColumnTasks(column.Status).Count;

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column.Name</strong>
                        <span class="badge bg-secondary">@columnCount</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height:65vh;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex align-items-center gap-2 mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (column.Index > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[column.Index - 1].Status)">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (column.Index < Columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[column.Index + 1].Status)">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_addingColumn == column.Status)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="_newTitle" />
                                    </div>
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="_newAssignee" />
                                    </div>
                                    <div class="mb-2">
                                        <select class="form-select form-select-sm" @bind="_newPriority">
                                            <option value="High">High</option>
                                            <option value="Medium">Medium</option>
                                            <option value="Low">Low</option>
                                        </select>
                                    </div>
                                    <div class="mb-2">
                                        <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
                                    </div>
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm" disabled="@_saving" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm" disabled="@_saving" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                disabled="@(_addingColumn is not null)"
                                @onclick="() => StartAdd(column.Status)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private const string StatusToDo = "To Do";
    private const string StatusInProgress = "In Progress";
    private const string StatusDone = "Done";

    private record ColumnDef(string Name, string Status, int Index);

    private static readonly ColumnDef[] Columns =
    [
        new("To Do", StatusToDo, 0),
        new("In Progress", StatusInProgress, 1),
        new("Done", StatusDone, 2)
    ];

    private List<TaskItem> _allTasks = [];
    private bool _loading = true;
    private bool _moving;
    private bool _saving;
    private string? _error;
    private string _searchTerm = string.Empty;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    private int OverdueCount => _allTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != StatusDone);

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(_searchTerm))
            tasks = tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
        return tasks;
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            _moving = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            _moving = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingColumn is null)
            return;

        try
        {
            _saving = true;
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);

            // If the task was created in a column other than its default, update its status
            if (created.Status != _addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingColumn);
                created = created with { Status = _addingColumn };
            }

            _allTasks.Add(created);
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

