@code {
    private const string StatusToDo = "To Do";
    private const string StatusInProgress = "In Progress";
    private const string StatusDone = "Done";

    private record ColumnDef(string Name, string Status, int Index);

    private static readonly ColumnDef[] Columns =
    [
        new("To Do", StatusToDo, 0),
        new("In Progress", StatusInProgress, 1),
        new("Done", StatusDone, 2)
    ];

    private List<TaskItem> _allTasks = [];
    private bool _loading = true;
    private bool _moving;
    private bool _saving;
    private string? _error;
    private string _searchTerm = string.Empty;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    private int OverdueCount => _allTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != StatusDone);

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(_searchTerm))
            tasks = tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
        return tasks;
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            _moving = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            _moving = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingColumn is null)
            return;

        try
        {
            _saving = true;
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);

            // If the task was created in a column other than its default, update its status
            if (created.Status != _addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingColumn);
                created = created with { Status = _addingColumn };
            }

            _allTasks.Add(created);
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}
"}

